#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        static char s[1000005];
        scanf("%s", s);
        int cnt = 0; int ok = 0;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '*') {
                cnt++;
                if (cnt >= K) { ok = 1; break; }
            } else cnt = 0;
        }
        printf(ok ? "YES\n" : "NO\n");
    }
    return 0;
}

