#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        s = next(it)
        cnt = 0
        ok = False
        for ch in s:
            if ch == '*':
                cnt += 1
                if cnt >= K:
                    ok = True
                    break
            else:
                cnt = 0
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

